import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicExample() {
        // [2,7,4,1,8,1] → 1 (canonical last-stone-weight example)
        assertEquals(1, new Solution().lastStoneWeight(new int[]{2, 7, 4, 1, 8, 1}));
    }

    @Test
    void emptyArray() {
        // No stones → 0
        assertEquals(0, new Solution().lastStoneWeight(new int[]{}));
    }

    @Test
    void singleStone() {
        // One stone → return its weight
        assertEquals(5, new Solution().lastStoneWeight(new int[]{5}));
    }

    @Test
    void twoEqualStones() {
        // Both destroyed → 0
        assertEquals(0, new Solution().lastStoneWeight(new int[]{3, 3}));
    }

    @Test
    void twoUnequalStones() {
        // Smash 7 and 4 → leftover 3
        assertEquals(3, new Solution().lastStoneWeight(new int[]{4, 7}));
    }

    @Test
    void allEqualEvenCount() {
        // 4 stones all weight 2: pairs cancel completely → 0
        assertEquals(0, new Solution().lastStoneWeight(new int[]{2, 2, 2, 2}));
    }

    @Test
    void allEqualOddCount() {
        // 3 stones all weight 5:
        // Smash 5 and 5 → 0 (destroyed); stones: [5]
        // One stone left → 5
        assertEquals(5, new Solution().lastStoneWeight(new int[]{5, 5, 5}));
    }
}
